// afterRender hook for Business Text panel
// Available: context.element (DOM), context.grafana.backendSrv, context.grafana.locationService
(function () {
  var root = (context && context.element) ? context.element : document;

  function q(id) { return root.querySelector ? root.querySelector('#' + id) : document.getElementById(id); }
  function set(id, val) { var el = q(id); if (el) el.textContent = val; }

  function fmtTime() {
    var d = new Date(), h = d.getHours(), m = d.getMinutes();
    return (h < 10 ? '0' + h : h) + ':' + (m < 10 ? '0' + m : m);
  }
  function fmtDate() {
    try { return new Date().toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' }); }
    catch (e) { return new Date().toDateString(); }
  }
  set('gh_now', fmtTime());
  set('gh_today', fmtDate());
  if (window.__ghClockInterval) clearInterval(window.__ghClockInterval);
  window.__ghClockInterval = setInterval(function () { set('gh_now', fmtTime()); }, 30000);

  // Use Grafana's backendSrv when available (cleaner auth handling), else fall back to fetch.
  var backendSrv = (context && context.grafana && context.grafana.backendSrv) ? context.grafana.backendSrv : null;
  function apiGet(path) {
    if (backendSrv && backendSrv.get) {
      try { return backendSrv.get(path).then(function (r) { return r; }).catch(function () { return null; }); }
      catch (e) { /* fall through */ }
    }
    return fetch(path, { credentials: 'include' })
      .then(function (r) { return r.ok ? r.json() : null; })
      .catch(function () { return null; });
  }

  // ─── Interactive search ───
  var input = q('ghsearch');
  var resultsEl = q('ghresults');
  var searchBox = q('gh_searchbox');

  if (searchBox && input) {
    searchBox.addEventListener('click', function () { input.focus(); });
  }

  if (input && resultsEl) {
    var debounceTimer;
    input.addEventListener('input', function () {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(function () {
        var term = input.value.trim();
        if (!term) { resultsEl.style.display = 'none'; return; }
        apiGet('/api/search?query=' + encodeURIComponent(term) + '&limit=15').then(function (j) {
          if (!j || !j.length) {
            resultsEl.innerHTML = '<div style="padding:28px;color:var(--gh-text-soft);text-align:center;font-size:13px;">No results for <strong style="color:var(--gh-text);">' + escapeHtml(term) + '</strong></div>';
            resultsEl.style.display = 'block';
            return;
          }
          var header = '<div style="padding:10px 20px 6px;font-size:10px;color:var(--gh-text-soft);text-transform:uppercase;letter-spacing:1px;font-weight:600;border-bottom:1px solid var(--gh-border-soft);">' + j.length + ' result' + (j.length > 1 ? 's' : '') + '</div>';
          var rows = j.map(function (x) {
            var folder = x.folderTitle || 'General';
            return '<a href="' + x.url + '" style="display:flex;align-items:center;gap:14px;padding:13px 20px;text-decoration:none;border-bottom:1px solid var(--gh-border-soft);transition:background 0.12s;">'
              + '<div style="width:32px;height:32px;border-radius:8px;background:rgba(244,104,0,0.12);display:flex;align-items:center;justify-content:center;flex-shrink:0;"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#F46800" stroke-width="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg></div>'
              + '<div style="flex:1;min-width:0;"><div style="font-size:10px;color:var(--gh-text-soft);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:2px;font-weight:600;">' + escapeHtml(folder) + '</div>'
              + '<div style="font-size:14px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + escapeHtml(x.title) + '</div></div>'
              + '<span style="color:var(--gh-text-soft);font-size:18px;flex-shrink:0;">\u2192</span></a>';
          }).join('');
          resultsEl.innerHTML = header + rows;
          resultsEl.style.display = 'block';
        });
      }, 180);
    });

    input.addEventListener('keydown', function (ev) {
      if (ev.key === 'Escape') {
        input.value = '';
        resultsEl.style.display = 'none';
        input.blur();
      } else if (ev.key === 'Enter') {
        var first = resultsEl.querySelector('a');
        if (first) {
          ev.preventDefault();
          window.location.href = first.getAttribute('href');
        }
      }
    });

    input.addEventListener('focus', function () {
      if (searchBox) {
        searchBox.style.borderColor = '#F46800';
        searchBox.style.boxShadow = 'var(--gh-shadow-focus)';
      }
    });
    input.addEventListener('blur', function () {
      setTimeout(function () { resultsEl.style.display = 'none'; }, 220);
      if (searchBox) {
        searchBox.style.borderColor = 'var(--gh-border)';
        searchBox.style.boxShadow = 'var(--gh-shadow)';
      }
    });
  }

  // ─── Tile hover (inline style changes are fine) ───
  var tiles = root.querySelectorAll ? root.querySelectorAll('.gh_tile') : [];
  tiles.forEach(function (t) {
    var accent = t.getAttribute('data-accent') || '244,104,0';
    var rgb = 'rgb(' + accent + ')';
    var origBorder = t.style.borderColor || 'rgba(' + accent + ',0.3)';
    t.addEventListener('mouseenter', function () {
      t.style.borderColor = rgb;
      t.style.boxShadow = '0 8px 24px rgba(' + accent + ',0.28)';
    });
    t.addEventListener('mouseleave', function () {
      t.style.borderColor = 'rgba(' + accent + ',0.3)';
      t.style.boxShadow = 'none';
    });
  });

  // ─── Live counts, user, version ───
  Promise.all([
    apiGet('/api/search?type=dash-db&limit=5000'),
    apiGet('/api/folders?limit=1000'),
    apiGet('/api/prometheus/grafana/api/v1/alerts'),
    apiGet('/api/datasources'),
    apiGet('/api/health'),
    apiGet('/api/user')
  ]).then(function (res) {
    var dashes = Array.isArray(res[0]) ? res[0].length : 0;
    var folders = Array.isArray(res[1]) ? res[1].length : 0;
    var alertsData = (res[2] && res[2].data && res[2].data.alerts) ? res[2].data.alerts : [];
    var firing = alertsData.filter(function (a) { return a.state === 'firing' || a.state === 'Alerting'; }).length;
    var totalAlerts = alertsData.length;
    var datasources = Array.isArray(res[3]) ? res[3] : [];
    var health = res[4];
    var user = res[5];

    set('gh_dash_count', dashes + ' dashboards');
    set('gh_folder_count', folders + ' folders');
    var alertLabel = firing > 0 ? (firing + ' firing') : (totalAlerts > 0 ? (totalAlerts + ' alerts') : '0 firing');
    set('gh_alert_count', alertLabel);

    var aDot = q('gh_dot_alert'), aTxt = q('gh_alert_count');
    if (firing > 0) {
      if (aDot) { aDot.style.background = '#EA4335'; aDot.style.boxShadow = '0 0 10px rgba(234,67,53,0.7)'; }
      if (aTxt) { aTxt.style.color = '#EA4335'; aTxt.style.fontWeight = '600'; }
    } else {
      if (aDot) { aDot.style.background = '#34A853'; aDot.style.boxShadow = '0 0 8px rgba(52,168,83,0.6)'; }
    }

    set('gh_ds_count', datasources.length + ' data source' + (datasources.length === 1 ? '' : 's'));

    if (health && health.version) { set('gh_ver_grafana', 'v' + health.version); }

    if (user) {
      var name = user.name || user.login || 'User';
      set('gh_username', name);
      var av = q('gh_avatar');
      if (av && user.avatarUrl) av.src = user.avatarUrl;
    }

    if (input && dashes > 0) {
      input.placeholder = 'Search ' + dashes + ' dashboards, alerts, data sources...';
    }

    // ─── LGTM component version detection via datasource proxy ───
    datasources.forEach(function (ds) {
      var path = null, type = null;
      if (ds.type === 'prometheus') { path = '/api/v1/status/buildinfo'; type = 'mimir'; }
      else if (ds.type === 'loki') { path = '/loki/api/v1/status/buildinfo'; type = 'loki'; }
      else if (ds.type === 'tempo') { path = '/api/status/buildinfo'; type = 'tempo'; }
      else if (ds.type === 'grafana-pyroscope-datasource' || ds.type === 'phlare-datasource') { path = '/api/v1/status/buildinfo'; type = 'pyroscope'; }
      if (!path) return;
      apiGet('/api/datasources/proxy/uid/' + ds.uid + path).then(function (j) {
        if (!j) return;
        var v = (j.data && j.data.version) || j.version || j.BuildVersion || null;
        if (v) set('gh_ver_' + type, 'v' + v);
      });
    });
  });

  function escapeHtml(s) {
    return String(s).replace(/[&<>"']/g, function (c) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
    });
  }
})();

options.styles:
/* ─── Theme variables ─── */
#ghroot {
  --gh-text:          #E5E9F0;
  --gh-text-soft:     #8B93A6;
  --gh-text-faint:    #4C566A;
  --gh-divider:       #2E3440;
  --gh-surface:       rgba(17,18,23,0.92);
  --gh-surface-alt:   rgba(17,18,23,0.6);
  --gh-surface-solid: #0b0c10;
  --gh-border:        #2E3440;
  --gh-border-soft:   rgba(255,255,255,0.04);
  --gh-kbd-bg:        #0f1014;
  --gh-kbd-fg:        #88C0D0;
  --gh-accent-fg:     #88C0D0;
  --gh-shadow:        0 10px 40px rgba(0,0,0,0.5);
  --gh-shadow-focus:  0 12px 48px rgba(244,104,0,0.2);
  --gh-shadow-drop:   0 24px 80px rgba(0,0,0,0.7);
  --gh-hover-bg:      rgba(244,104,0,0.14);
  --gh-glow-blue:     rgba(66,133,244,0.07);
  --gh-glow-orange:   rgba(244,104,0,0.06);
  --gh-glow-green:    rgba(163,190,140,0.03);
  --gh-tile-alpha:    0.14;
  --gh-res-bg:        rgba(17,18,23,0.5);
}

body.theme-light #ghroot {
  --gh-text:          #1F2937;
  --gh-text-soft:     #6B7280;
  --gh-text-faint:    #9CA3AF;
  --gh-divider:       #E5E7EB;
  --gh-surface:       rgba(255,255,255,0.95);
  --gh-surface-alt:   rgba(255,255,255,0.8);
  --gh-surface-solid: #FFFFFF;
  --gh-border:        #E5E7EB;
  --gh-border-soft:   rgba(0,0,0,0.05);
  --gh-kbd-bg:        #F9FAFB;
  --gh-kbd-fg:        #2563EB;
  --gh-accent-fg:     #2563EB;
  --gh-shadow:        0 8px 28px rgba(0,0,0,0.08);
  --gh-shadow-focus:  0 12px 36px rgba(244,104,0,0.22);
  --gh-shadow-drop:   0 16px 48px rgba(0,0,0,0.15);
  --gh-hover-bg:      rgba(244,104,0,0.1);
  --gh-glow-blue:     rgba(66,133,244,0.05);
  --gh-glow-orange:   rgba(244,104,0,0.05);
  --gh-glow-green:    rgba(163,190,140,0.04);
  --gh-tile-alpha:    0.10;
  --gh-res-bg:        rgba(255,255,255,0.7);
}

/* ─── Animations ─── */
@keyframes gh_pulse { 0%,100% { transform:scale(1); opacity:0.9; } 50% { transform:scale(1.15); opacity:1; } }
@keyframes gh_spin { from { transform:rotate(0deg); } to { transform:rotate(360deg); } }
@keyframes gh_fade_up { from { opacity:0; transform:translateY(12px); } to { opacity:1; transform:translateY(0); } }

#ghroot { animation: gh_fade_up 0.6s ease-out; color: var(--gh-text); }
#gh_dot { animation: gh_pulse 2.4s ease-in-out infinite; transform-origin: center; }
#gh_orbit_outer { animation: gh_spin 40s linear infinite; transform-origin: 50px 50px; }
#gh_orbit_mid { animation: gh_spin 25s linear infinite reverse; transform-origin: 50px 50px; }

/* ─── Input & results ─── */
#ghsearch { color: var(--gh-text); }
#ghsearch::placeholder { color: var(--gh-text-soft); opacity: 1; }
#ghsearch:focus { outline: none; }
#ghresults::-webkit-scrollbar { width: 8px; }
#ghresults::-webkit-scrollbar-track { background: transparent; }
#ghresults::-webkit-scrollbar-thumb { background: var(--gh-border); border-radius: 4px; }
#ghresults::-webkit-scrollbar-thumb:hover { background: var(--gh-text-faint); }
#ghresults a:hover { background: var(--gh-hover-bg) !important; }
#ghresults a { color: var(--gh-text) !important; }

/* ─── Tile & resource hover ─── */
.gh_tile, .gh_res { transition: all 0.25s ease; }
.gh_tile:hover { transform: translateY(-3px); }
.gh_res:hover { transform: translateY(-2px); border-color: var(--gh-accent-fg) !important; }
